@app.route("/tokens", methods=["POST"])
def create_token():
    data = request.get_json(silent=True) or {}
    subject = data.get("subject", "service-account")
    scope = data.get("scope", "")
    token = data.get("token") or secrets.token_urlsafe(32)

    db = get_db()
    try:
        db.execute(
            """
            INSERT INTO access_tokens (token, subject, scope, active)
            VALUES (?, ?, ?, 1)
            """,
            (token, subject, scope),
        )
        db.commit()
    except sqlite3.IntegrityError:
        return jsonify({"error": "token_already_exists"}), 409

    return jsonify({"access_token": token, "subject": subject, "scope": scope}), 201


@app.route("/tokens/<token_value>/revoke", methods=["POST"])
def revoke_token(token_value):
    db = get_db()
    cursor = db.execute(
        "UPDATE access_tokens SET active = 0 WHERE token = ? AND active = 1",
        (token_value,),
    )
    db.commit()

    if cursor.rowcount == 0:
        return jsonify({"error": "token_not_found"}), 404

    return jsonify({"revoked": True, "token": token_value}), 200


